package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.HrAkeMappingSlice;
import be.schaubroeck.lpb.tools.HrReductieType;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.RekenElement;
import be.schaubroeck.lpb.tools.Vergoeding;
import be.schaubroeck.lpb.tools.api.dto.AardKodeExtensieDTO;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
