import be.schaubroeck.lpb.tools.service.AardKodeExtensieService;
import be.schaubroeck.lpb.tools.service.util.StandaardAlService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import lombok.Data;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.Collection;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Slf4j
public class CachedAardKodeExtensieService extends StandaardALCachedService<AardKodeExtensie> implements CachedService, AardKodeExtensieService {

    private static final ThreadLocal<CachedAardKodeExtensieBuffer> BUFFER = new ThreadLocal<>();
    @Autowired
    private AardKodeExtensieService aardKodeExtensieService;

    public CachedAardKodeExtensieService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    private static CachedAardKodeExtensieBuffer getBuffer() {
        CachedAardKodeExtensieBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedAardKodeExtensieBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Override
    public AardKodeExtensie getAkeByTijdperkAardCodeExtensie(Integer tp, Integer aard, Integer kode, Integer ext) {
        TimeLogContext.getInstance().startTimeLogging("CachedAardKodeExtensieService.getAkeByTijdperkAardCodeExtensie");
        CachedAardKodeExtensieBuffer buffer = CachedAardKodeExtensieService.getBuffer();
        AardKodeExtensieKey key = new AardKodeExtensieKey(tp, aard, kode, ext);
        AardKodeExtensie result = buffer.getByKey(key);
        if (result == null) {
            result = aardKodeExtensieService.getAkeByTijdperkAardCodeExtensie(tp, aard, kode, ext);
            if (result == null) {
                log.warn("AardKodeExtensie {}-{}-{}-{} niet gevonden", tp, aard, kode, ext);
            } else {
                buffer.put(key, result);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public AardKodeExtensie getAkeByTijdperkAardCodeExtensie(AkeTijdperk tp, AardKodeExt aard, Integer kode, Integer ext) {
        return getAkeByTijdperkAardCodeExtensie(tp.getCode(), aard.getCode(), kode, ext);
    }

    @Override
    public Boolean isAfwezigheidsCode(AardKodeExtensie looncode) {
        TimeLogContext.getInstance().startTimeLogging("CachedAardKodeExtensieService.isAfwezigheidsCode");
        CachedAardKodeExtensieBuffer buffer = CachedAardKodeExtensieService.getBuffer();
        AardKodeExtensieKey key = new AardKodeExtensieKey(looncode, "");
        Boolean result = buffer.isAfwezigheidsCode(key);
        if (result == null) {
            result = aardKodeExtensieService.isAfwezigheidsCode(looncode);
            buffer.putIsAfwezigheidsCode(key, result);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public List<AardKodeExtensie> findByTpAardCode(int tijdperk, int aard, int code) {
        return aardKodeExtensieService.findByTpAardCode(tijdperk, aard, code);
    }

    @Override
    public AardKodeExtensie getById(Integer id, String fetchFields) {
        return getById(id);
    }

    @Override
    public AardKodeExtensie getById(Integer id) {
        TimeLogContext.getInstance().startTimeLogging("CachedAardKodeExtensieService.getById");
        CachedAardKodeExtensieBuffer buffer = CachedAardKodeExtensieService.getBuffer();
        AardKodeExtensie result = buffer.getById(id);
        if (result == null) {
            result = aardKodeExtensieService.getById(id, "groepen");
            AardKodeExtensieKey key = new AardKodeExtensieKey(result.getTijdperk(), result.getAard(), result.getCode(), result.getExtensie());
            buffer.put(key, result);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public void clearCache() {
        CachedAardKodeExtensieService.getBuffer().clear();
    }

    @Override
    public StandaardAlService<AardKodeExtensie> standaardAlService() {
        return (StandaardAlService<AardKodeExtensie>) aardKodeExtensieService;
    }

    @Override
    public AardKodeExtensie getByVergoeding(Vergoeding vergoeding) {
        return getAkeByTijdperkAardCodeExtensie(vergoeding.getTijdperk(), AardKodeExt.V_KODE_EXT.getCode(), vergoeding.getCode(),
                vergoeding.getExtensie());
    }

    @Override
    public AardKodeExtensie getByNlpPrestatie(NlpPrestatie prestatie) {
        return getAkeByTijdperkAardCodeExtensie(prestatie.getTijdperk(), prestatie.getAard(), prestatie.getCode(), prestatie.getExtensie());
    }

    @Override
    public AardKodeExtensie getByRekenElement(RekenElement element) {
        return getAkeByTijdperkAardCodeExtensie(element.getTijdperk(), element.getAard(), element.getCode(), element.getExtensie());
    }

    @Override
    public List<AardKodeExtensie> findAkesWettelijkeFeestdagen() {
        return aardKodeExtensieService.findAkesWettelijkeFeestdagen();
    }

    @Override
    public List<AardKodeExtensie> findByTijdperkenAke(List<Integer> tijdperken, Integer aard, Integer kode, Integer ext) {
        return aardKodeExtensieService.findByTijdperkenAke(tijdperken, aard, kode, ext);
    }

    @Override
    public List<AardKodeExtensie> findByTijdperkenMultipleAkes(List<Integer> tijdperken, List<AardKodeExtensie> ake) {
        return aardKodeExtensieService.findByTijdperkenMultipleAkes(tijdperken, ake);
    }

    @Override
    public List<AardKodeExtensie> findByTijdperkAard(Integer tijdperk, Integer aard) {
        return aardKodeExtensieService.findByTijdperkAard(tijdperk, aard);
    }

    @Override
    public List<AardKodeExtensie> findByTijdperk(Integer tijdperk) {
        return aardKodeExtensieService.findByTijdperk(tijdperk);
    }

    @Override
    public List<AardKodeExtensie> findByIds(List<Integer> ids) {
        return aardKodeExtensieService.findByIds(ids);
    }

    @Override
    public List<AardKodeExtensie> findByTijdperkenAndAard(List<Integer> tijdperken, List<Integer> aarden) {
        return aardKodeExtensieService.findByTijdperkenAndAard(tijdperken, aarden);
    }

    @Override
    public List<AardKodeExtensie> findByOmschrijving(
            AkeTijdperk tijdperk, AardKodeExt aard, String filter) {
        return aardKodeExtensieService.findByOmschrijving(tijdperk, aard, filter);
    }

    @Override
    public List<AardKodeExtensieDTO> getAardCodeExtentieByHoedanigheid(Hoedanigheid hoedanigheid) {
        return aardKodeExtensieService.getAardCodeExtentieByHoedanigheid(hoedanigheid);
    }

    @Override
    public List<AardKodeExtensie> findLangdurigeAfwezigheden() {
        return aardKodeExtensieService.findLangdurigeAfwezigheden();
    }

    @Override
    public List<AardKodeExtensie> findUitzonderlijkeAfwezigheden() {
        return aardKodeExtensieService.findUitzonderlijkeAfwezigheden();
    }

    @Override
    public Collection<AardKodeExtensie> getAardKodeExtensies(HrAkeMappingSlice hrAkeMappingSlice) {
        return aardKodeExtensieService.getAardKodeExtensies(hrAkeMappingSlice);
    }

    @Override
    public List<AardKodeExtensie> findAll() {
        return aardKodeExtensieService.findAll();
    }

    @Override
    public AardKodeExtensie create(AardKodeExtensie constant) {
        return aardKodeExtensieService.create(constant);
    }

    @Override
    public void update(AardKodeExtensie constant) {
        aardKodeExtensieService.update(constant);
    }

    @Override
    public void delete(AardKodeExtensie constant) {
        aardKodeExtensieService.delete(constant);
    }

    @Override
    public AardKodeExtensie getByCriteria(CriteriaBuilder cb) {
        return aardKodeExtensieService.getByCriteria(cb);
    }

    @Override
    public List<AardKodeExtensie> findAll(String fetchFields) {
        return aardKodeExtensieService.findAll(fetchFields);
    }

    @Override
    public List<AardKodeExtensie> findByCriteria(CriteriaBuilder cb) {
        return aardKodeExtensieService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return aardKodeExtensieService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, AardKodeExtensie> cacheByCriteria(CriteriaBuilder cb) {
        return aardKodeExtensieService.cacheByCriteria(cb);
    }

    @Override
    public AardKodeExtensie getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return aardKodeExtensieService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<AardKodeExtensie> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return aardKodeExtensieService.findByCriteriaTemporalFree(cb);
    }

    @Override
    public Integer getMaxTellerKode() {
        return aardKodeExtensieService.getMaxTellerKode();
    }

    @Override
    public List<AardKodeExtensie> findByAard(Integer aard) {
        return aardKodeExtensieService.findByAard(aard);
    }

    @Override
    public List<AardKodeExtensie> findByReductieType(HrReductieType reductieType) {
        return aardKodeExtensieService.findByReductieType(reductieType);
    }

    private static class CachedAardKodeExtensieBuffer {

        private final Map<AardKodeExtensieKey, AardKodeExtensie> aardKodeExtensieBuffer = new HashMap<>();
        private final Map<AardKodeExtensieKey, Boolean> isAfwezigheidsCodeBuffer = new HashMap<>();
        private final Map<Integer, AardKodeExtensie> akeIdBuffer = new HashMap<>();

        public AardKodeExtensie getByKey(AardKodeExtensieKey key) {
            return aardKodeExtensieBuffer.get(key);
        }

        public AardKodeExtensie getById(Integer id) {
            return akeIdBuffer.get(id);
        }

        public void put(AardKodeExtensieKey key, AardKodeExtensie aardKodeExtensie) {
            aardKodeExtensieBuffer.put(key, aardKodeExtensie);
            akeIdBuffer.put(aardKodeExtensie.getId(), aardKodeExtensie);
        }

        public void clear() {
            this.aardKodeExtensieBuffer.clear();
            this.akeIdBuffer.clear();
            this.isAfwezigheidsCodeBuffer.clear();
        }

        public void putIsAfwezigheidsCode(AardKodeExtensieKey key, Boolean isAfwezigheidsCode) {
            isAfwezigheidsCodeBuffer.put(key, isAfwezigheidsCode);
        }

        public Boolean isAfwezigheidsCode(AardKodeExtensieKey key) {
            return isAfwezigheidsCodeBuffer.get(key);
        }
    }

    @Data
    @RequiredArgsConstructor
    private static class AardKodeExtensieKey {

        private final int tijdperk;
        private final int aard;
        private final int code;
        private final int extensie;
        private final String groepnaam;

        public AardKodeExtensieKey(int tijdperk, int aard, int code, int extensie) {
            this(tijdperk, aard, code, extensie, "");
        }

        public AardKodeExtensieKey(AardKodeExtensie looncode, String groepnaam) {
            this(looncode.getTijdperk(), looncode.getAard(), looncode.getCode(), looncode.getExtensie(), groepnaam);
        }
    }

}
